  ('aboriginal-a5729396-moex-00213', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '「原住民學生人數達全校學生人數二分之一之原住民重點學校，其主任、校長，應優先聘任、遴選原 住民族已具主任、校長資格者。」請問上述內容係規定在那一部法規範？', '["原住民族基本法", "原住民族語言發展法", "原住民族教育法", "原住民身分法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
